import type { Meta, StoryObj } from '@storybook/react-vite';
import { message } from './Message';
import { Button } from '../Button';
import { Space } from '../Space';

/**
 * `message` is an imperative toast API rather than a declarative component, so
 * there is no element to control through args. Each story renders a trigger
 * that calls `message.success(...)`, `message.error(...)`, and friends. The
 * toast mounts itself near the top of the viewport and auto-dismisses.
 */
const meta = {
  title: 'Components/Message',
  tags: ['autodocs'],
  parameters: {
    docs: {
      description: {
        component:
          'Imperative toast notifications. Call `message(...)` or the typed helpers ' +
          '`message.success`, `message.warning`, `message.info` and `message.error` to ' +
          'show a short, auto-dismissing message. Each call returns a handle with a ' +
          '`close()` method, and `message.closeAll()` clears the stack.',
      },
    },
  },
} satisfies Meta;

export default meta;
type Story = StoryObj<typeof meta>;

export const Types: Story = {
  render: () => (
    <Space wrap>
      <Button type="success" onClick={() => message.success('Changes saved')}>
        Success
      </Button>
      <Button type="warning" onClick={() => message.warning('Storage almost full')}>
        Warning
      </Button>
      <Button type="info" onClick={() => message.info('A new version is available')}>
        Info
      </Button>
      <Button type="danger" onClick={() => message.error('Something went wrong')}>
        Error
      </Button>
    </Space>
  ),
};

export const Closable: Story = {
  name: 'Closable and persistent',
  render: () => (
    <Space wrap>
      <Button
        onClick={() =>
          message.info({ message: 'Click the cross to dismiss me', showClose: true })
        }
      >
        Closable
      </Button>
      <Button
        onClick={() =>
          message.warning({
            message: 'I stay until closed',
            duration: 0,
            showClose: true,
          })
        }
      >
        Persistent
      </Button>
    </Space>
  ),
};

export const Stacked: Story = {
  name: 'Stacked messages',
  render: () => (
    <Space wrap>
      <Button
        type="primary"
        onClick={() => {
          message.success('First message');
          message.info('Second message');
          message.warning('Third message');
        }}
      >
        Show three
      </Button>
      <Button onClick={() => message.closeAll()}>Close all</Button>
    </Space>
  ),
};

import { useEffect, useRef, useState, type CSSProperties, type ReactNode } from 'react';
import { createRoot, type Root } from 'react-dom/client';
import { cls, useNamespace } from '../../utils';
import { CloseIcon, StatusIcon, type StatusType } from './StatusIcon';

export type MessageType = StatusType;

export interface MessageOptions {
  /** Body content. */
  message?: ReactNode;
  /** Visual variant. Default `'info'`. */
  type?: MessageType;
  /** Auto-dismiss delay in ms. `0` keeps the toast until closed. Default `3000`. */
  duration?: number;
  /** Show a close button. */
  showClose?: boolean;
  /** Center the text. */
  center?: boolean;
  /** Distance in px from the top of the viewport for the first toast. Default `16`. */
  offset?: number;
  /** Extra class on the toast element. */
  className?: string;
  /** Fired after the toast has closed. */
  onClose?: () => void;
}

/** Imperative handle returned by every `message()` call. */
export interface MessageHandle {
  close: () => void;
}

interface MessageItem extends MessageOptions {
  id: number;
}

let seed = 0;
let root: Root | null = null;
let container: HTMLElement | null = null;
let items: MessageItem[] = [];

const DEFAULT_OFFSET = 16;
/** Vertical gap between stacked toasts, in px. */
const GAP = 16;

function isBrowser(): boolean {
  return typeof document !== 'undefined';
}

function ensureRoot(): Root | null {
  if (!isBrowser()) return null;
  if (!root) {
    container = document.createElement('div');
    container.className = 'ec-message-container';
    document.body.appendChild(container);
    root = createRoot(container);
  }
  return root;
}

function flush(): void {
  root?.render(<MessageList items={items} onRemove={remove} />);
}

function remove(id: number): void {
  const item = items.find((entry) => entry.id === id);
  items = items.filter((entry) => entry.id !== id);
  flush();
  item?.onClose?.();
}

interface MessageToastProps {
  item: MessageItem;
  /** Cumulative top offset (px) for this toast within the stack. */
  top: number;
  onRemove: (id: number) => void;
}

function MessageToast({ item, top, onRemove }: MessageToastProps) {
  const ns = useNamespace('message');
  const { type = 'info', duration = 3000, showClose, center, message } = item;
  const [visible, setVisible] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  // Trigger the enter transition on the next frame after mount.
  useEffect(() => {
    const raf = requestAnimationFrame(() => setVisible(true));
    return () => cancelAnimationFrame(raf);
  }, []);

  useEffect(() => {
    if (duration <= 0) return;
    const timer = window.setTimeout(() => onRemove(item.id), duration);
    return () => window.clearTimeout(timer);
  }, [duration, item.id, onRemove]);

  const classes = cls(
    ns.b(),
    ns.m(type),
    ns.is('center', center),
    ns.is('closable', showClose),
    visible && ns.is('visible'),
    item.className,
  );

  const style: CSSProperties = { top: `${top}px` };

  return (
    <div ref={ref} className={classes} style={style} role="alert" aria-live="polite">
      <span className={ns.e('icon')}>
        <StatusIcon type={type} />
      </span>
      <span className={ns.e('content')}>{message}</span>
      {showClose && (
        <button
          type="button"
          className={ns.e('closebtn')}
          aria-label="Close"
          onClick={() => onRemove(item.id)}
        >
          <CloseIcon />
        </button>
      )}
    </div>
  );
}

function MessageList({
  items: list,
  onRemove,
}: {
  items: MessageItem[];
  onRemove: (id: number) => void;
}) {
  let offset = 0;
  return (
    <>
      {list.map((item, index) => {
        const base = item.offset ?? DEFAULT_OFFSET;
        // First toast sits at its own offset; later toasts stack below the
        // previous ones with a fixed gap.
        const top = index === 0 ? base : offset + GAP;
        offset = top + 40; // approximate toast height for the next iteration
        return <MessageToast key={item.id} item={item} top={top} onRemove={onRemove} />;
      })}
    </>
  );
}

function normalize(options: MessageOptions | string): MessageOptions {
  return typeof options === 'string' ? { message: options } : options;
}

function open(options: MessageOptions | string): MessageHandle {
  const opts = normalize(options);
  const id = ++seed;

  if (!ensureRoot()) {
    // SSR / non-browser: return an inert handle.
    return { close: () => {} };
  }

  items = [...items, { ...opts, id }];
  flush();

  return { close: () => remove(id) };
}

type MessageFn = (options: MessageOptions | string) => MessageHandle;

interface MessageApi extends MessageFn {
  success: MessageFn;
  warning: MessageFn;
  info: MessageFn;
  error: MessageFn;
  /** Close every open message. */
  closeAll: () => void;
}

function withType(type: MessageType): MessageFn {
  return (options) => open({ ...normalize(options), type });
}

const message = open as MessageApi;
message.success = withType('success');
message.warning = withType('warning');
message.info = withType('info');
message.error = withType('error');
message.closeAll = () => {
  for (const item of [...items]) remove(item.id);
};

export { message };
/** Alias for the callable `message` API. */
export const Message = message;

.ec-message {
  --ec-message-bg-color: var(--ec-color-info-light-9);
  --ec-message-border-color: var(--ec-color-info-light-8);
  --ec-message-text-color: var(--ec-text-color-regular);
  --ec-message-icon-color: var(--ec-color-info);
  --ec-message-close-color: var(--ec-text-color-placeholder, var(--ec-text-color-secondary));

  display: inline-flex;
  align-items: center;
  box-sizing: border-box;
  gap: 8px;
  position: fixed;
  left: 50%;
  top: 16px;
  z-index: var(--ec-index-popper);
  min-width: 280px;
  max-width: calc(100vw - 32px);
  padding: 11px 16px;
  font-family: inherit;
  font-size: var(--ec-font-size-base);
  line-height: 1.4;
  color: var(--ec-message-text-color);
  background-color: var(--ec-message-bg-color);
  border: var(--ec-border-width) var(--ec-border-style) var(--ec-message-border-color);
  border-radius: var(--ec-border-radius-base);
  box-shadow: var(--ec-box-shadow-light);
  opacity: 0;
  transform: translate(-50%, -24px);
  transition:
    opacity 0.3s,
    transform 0.4s,
    top 0.4s;
}

.ec-message.is-visible {
  opacity: 1;
  transform: translate(-50%, 0);
}

.ec-message.is-center {
  justify-content: center;
}

.ec-message__icon {
  display: inline-flex;
  align-items: center;
  flex-shrink: 0;
  font-size: 16px;
  color: var(--ec-message-icon-color);
}

.ec-message__content {
  flex: 1;
  overflow-wrap: anywhere;
}

.ec-message__closebtn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  box-sizing: border-box;
  width: 16px;
  height: 16px;
  padding: 0;
  margin: 0;
  font-size: 14px;
  color: var(--ec-message-close-color);
  cursor: pointer;
  background-color: transparent;
  border: none;
  border-radius: var(--ec-border-radius-base);
  outline: none;
  transition: color 0.2s;
}

.ec-message__closebtn:hover {
  color: var(--ec-message-text-color);
}

.ec-message__closebtn:focus-visible {
  outline: 2px solid var(--ec-color-primary-light-5);
  outline-offset: 1px;
}

/* ---- Types ---- */
.ec-message--success {
  --ec-message-bg-color: var(--ec-color-success-light-9);
  --ec-message-border-color: var(--ec-color-success-light-8);
  --ec-message-icon-color: var(--ec-color-success);
}

.ec-message--warning {
  --ec-message-bg-color: var(--ec-color-warning-light-9);
  --ec-message-border-color: var(--ec-color-warning-light-8);
  --ec-message-icon-color: var(--ec-color-warning);
}

.ec-message--info {
  --ec-message-bg-color: var(--ec-color-info-light-9);
  --ec-message-border-color: var(--ec-color-info-light-8);
  --ec-message-icon-color: var(--ec-color-info);
}

.ec-message--error {
  --ec-message-bg-color: var(--ec-color-danger-light-9);
  --ec-message-border-color: var(--ec-color-danger-light-8);
  --ec-message-icon-color: var(--ec-color-danger);
}
